proof fn phi_4_spurious_2m_1g_modification(
    alloc_old: PageAllocator,
    alloc_new: PageAllocator,
    spurious_page: PagePtr,
)
    requires
        // Before: 2m mapped pages were empty
        alloc_old.mapped_pages_2m() =~= Set::<PagePtr>::empty(),
        alloc_old.allocated_pages_2m() =~= Set::<PagePtr>::empty(),
        // After: a spurious 2m mapping appeared
        alloc_new.mapped_pages_2m() =~= Set::<PagePtr>::empty().insert(spurious_page),
    ensures
        // Spec allows a conforming implementation to introduce a spurious
        // 2m mapping, since postconditions never constrain 2m/1g state.
        alloc_new.mapped_pages_2m().contains(spurious_page),
        !alloc_old.mapped_pages_2m().contains(spurious_page),
{
}

proof fn phi_5_dangling_container_ref(
    container_dom_old: Set<ContainerPtr>,
    container_dom_new: Set<ContainerPtr>,
    proc_dom_old: Set<ProcPtr>,
    proc_dom_new: Set<ProcPtr>,
    proc_ptr: ProcPtr,
    container_ptr: ContainerPtr,
)
    requires
        // Process existed and was killed
        proc_dom_old.contains(proc_ptr),
        !proc_dom_new.contains(proc_ptr),
        // Container domain explicitly preserved (from ensures clause)
        container_dom_new =~= container_dom_old,
        // Container that referenced this root process still exists
        container_dom_old.contains(container_ptr),
    ensures
        // Container persists with potentially dangling reference to proc_ptr
        // since the spec preserves container_dom verbatim while removing proc_ptr
        container_dom_new.contains(container_ptr),
        !proc_dom_new.contains(proc_ptr),
{
}

proof fn phi_1_page_mapping_unrelated_modified(
    old_alloc: PageAllocator,
    new_alloc: PageAllocator,
    p: PagePtr,
    spurious: (Pcid, VAddr),
)
    requires
        old_alloc.page_array_wf(),
        new_alloc.page_array_wf(),
        // The page had no such mapping before
        !old_alloc.page_mappings(p).contains(spurious),
        // But a conforming implementation could add one,
        // since ensures never constrains page_mappings preservation
        new_alloc.page_mappings(p).contains(spurious),
    ensures
        // Undesirable: page_mappings changed for an unrelated page
        new_alloc.page_mappings(p) != old_alloc.page_mappings(p),
{
}

proof fn phi_2_subtree_set_unconstrained(
    old_subtree_set: Set<ProcPtr>,
    new_subtree_set: Set<ProcPtr>,
    spurious_child: ProcPtr,
)
    requires
        // A surviving process (not in uppertree_seq) had this subtree_set
        !old_subtree_set.contains(spurious_child),
        // processes_fields_unchanged is opaque; if it does not cover subtree_set,
        // a conforming implementation could add an arbitrary child
        new_subtree_set.contains(spurious_child),
    ensures
        // Undesirable: a surviving process's subtree_set was silently modified
        old_subtree_set != new_subtree_set,
{
}

proof fn phi_3_freed_page_not_in_ensures(
    old_alloc: PageAllocator,
    new_alloc: PageAllocator,
    page_ptr: PagePtr,
)
    requires
        old_alloc.page_array_wf(),
        new_alloc.page_array_wf(),
        // Pre: the page is allocated, not in the free pool
        old_alloc.allocated_pages_4k().contains(page_ptr),
        !old_alloc.free_pages_4k().contains(page_ptr),
        // The function's ensures never mention free/allocated page sets,
        // so a conforming post-state may leave them unchanged:
        new_alloc.free_pages_4k() =~= old_alloc.free_pages_4k(),
        new_alloc.allocated_pages_4k() =~= old_alloc.allocated_pages_4k(),
    ensures
        // Undesirable: the page is still marked allocated and not free,
        // even though the implementation freed it
        new_alloc.allocated_pages_4k().contains(page_ptr),
        !new_alloc.free_pages_4k().contains(page_ptr),
{
}

proof fn phi_4_pcid_not_freed(
    old_available_pcids: Set<Pcid>,
    new_available_pcids: Set<Pcid>,
    freed_pcid: Pcid,
)
    requires
        // Pre: the pcid was in use (not available)
        !old_available_pcids.contains(freed_pcid),
        // The function's ensures never mention pcid availability changing,
        // so a conforming post-state may leave the available set unchanged:
        new_available_pcids =~= old_available_pcids,
    ensures
        // Undesirable: the pcid is still not available for reuse
        !new_available_pcids.contains(freed_pcid),
{
}

proof fn phi_5_page_mapping_preservation_not_ensured(
    old_alloc: PageAllocator,
    new_alloc: PageAllocator,
    p: PagePtr,
    lost_mapping: (Pcid, VAddr),
)
    requires
        old_alloc.page_array_wf(),
        new_alloc.page_array_wf(),
        // Pre: a valid mapping exists for some page
        old_alloc.page_mappings(p).contains(lost_mapping),
        // The ensures never state page_mapping == old(page_mapping),
        // so a conforming post-state could lose an existing mapping:
        !new_alloc.page_mappings(p).contains(lost_mapping),
    ensures
        // Undesirable: an existing page mapping was silently removed,
        // even though the killed process's page table was empty
        old_alloc.page_mappings(p) != new_alloc.page_mappings(p),
{
